import { describe, it, expect } from 'vitest';
import { coordinateToShard, getAdjacentShards, SHARD_SIZE } from '../void-regional-shards';
import type { GameCoordinate } from '../void-game-types';

describe('void-regional-shards', () => {
  it('chunks hex coordinates predictably', () => {
    const origin: GameCoordinate = { seed: 1, dimension: 5, hexQ: 0, hexR: 0, hexS: 0, tick: 1 };
    const shard = coordinateToShard(origin);
    
    expect(shard.shardId).toBe('shard-dim5-q0r0');
    expect(shard.chunkQ).toBe(0);
    expect(shard.chunkR).toBe(0);
  });

  it('groups large distances into the same shard', () => {
    // SHARD_SIZE is 1000. So anything from 0 to 999 is chunk 0.
    const edgeCoord: GameCoordinate = { seed: 1, dimension: 5, hexQ: SHARD_SIZE - 1, hexR: 200, hexS: -1199, tick: 1 };
    const shard = coordinateToShard(edgeCoord);
    
    expect(shard.shardId).toBe('shard-dim5-q0r0');
  });

  it('transitions to a different shard across boundaries', () => {
    const boundaryCoord: GameCoordinate = { seed: 1, dimension: 5, hexQ: SHARD_SIZE + 5, hexR: -SHARD_SIZE - 5, hexS: 0, tick: 1 };
    const shard = coordinateToShard(boundaryCoord);
    
    expect(shard.shardId).toBe('shard-dim5-q1r-2');
    expect(shard.chunkQ).toBe(1);
    expect(shard.chunkR).toBe(-2);
  });

  it('generates 6 adjacent shards correctly', () => {
    const shard = coordinateToShard({ seed: 1, dimension: 0, hexQ: 0, hexR: 0, hexS: 0, tick: 1 });
    const adjacent = getAdjacentShards(shard);
    
    expect(adjacent.length).toBe(6);
    expect(adjacent).toContain('shard-dim0-q1r0');
    expect(adjacent).toContain('shard-dim0-q0r1');
    expect(adjacent).toContain('shard-dim0-q-1r1');
  });
});
